ps.pstext:
if !IsFeatureImplemented(FEAT_SME2) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt(Rn);
let m : integer = UInt(Rm);
let g : integer = UInt('1'::PNg);
let nreg : integer{} = 2;
let tstride : integer = 8;
let t : integer = UInt(T::'0'::Zt);
let esize : integer{} = 16;

if !IsFeatureImplemented(FEAT_SME2) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt(Rn);
let m : integer = UInt(Rm);
let g : integer = UInt('1'::PNg);
let nreg : integer{} = 4;
let tstride : integer = 4;
let t : integer = UInt(T::'00'::Zt);
let esize : integer{} = 16;

CheckStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV esize;
let mbytes : integer{} = esize DIV 8;
var offset : bits(64);
var base : bits(64);
var addr : bits(64);
var src : bits(VL);
let pred : bits(PL) = P{}(g);
let mask : bits(PL * nreg) = CounterToPredicate{}(pred[15:0]);
let contiguous : boolean = TRUE;
let nontemporal : boolean = TRUE;
var transfer : integer = t;
let tagchecked : boolean = TRUE;
let accdesc : AccessDescriptor = CreateAccDescSVE(MemOp_STORE, nontemporal, contiguous,
                                                     tagchecked);

if !AnyActiveElement{PL*nreg}(mask, esize) then
    if n == 31 && ConstrainUnpredictableBool(Unpredictable_CHECKSPNONEACTIVE) then
        CheckSPAlignment();
    end;
else
    if n == 31 then CheckSPAlignment(); end;
end;

base = if n == 31 then SP{64}() else X{64}(n);
offset = X{64}(m);
addr = AddressAdd(base, UInt(offset) * mbytes, accdesc);

for r = 0 to nreg-1 do
    src = Z{VL}(transfer);
    for e = 0 to elements-1 do
        if ActivePredicateElement{PL*nreg}(mask, r * elements + e, esize) then
            Mem{esize}(addr, accdesc) = src[e*:esize];
        end;
        addr = AddressIncrement(addr, mbytes, accdesc);
    end;
    transfer = transfer + tstride;
end;
